"""
Parameterized generator for GH482_openrag_167.

Source PR:    https://github.com/linagora/openrag/pull/167
Source Issue: N/A

Seed varies: renames 'add_file' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH482_openrag_167'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH482_openrag_167'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('add_file', 'add_file' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH482_openrag_167',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'linagora/openrag',
                "pr_number": 167,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/linagora/openrag/pull/167",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'openrag/components/files.py': 'from pathlib import Path\nimport aiofiles\nfrom fastapi import UploadFile\nimport consts\nimport time\nimport secrets\nimport asyncio\nfrom typing import Dict, Optional\n\n\ndef make_unique_filename(filename: str) -> Path:\n    ts = int(time.time() * 1000)\n    rand = secrets.token_hex(2)\n    unique_name = f"{ts}_{rand}_{filename}"\n    return unique_name\n\n\nasync def save_file_to_disk(\n    file: UploadFile,\n    dest_dir: Path,\n    chunk_size: int = consts.FILE_READ_CHUNK_SIZE,\n    with_random_prefix: bool = False,\n) -> Path:\n    """\n    Save file to disk by chunks, to avoid reading the whole file at once in memory.\n    Returns the path to the saved file.\n    """\n    dest_dir.mkdir(parents=True, exist_ok=True)\n\n    if with_random_prefix:\n        filename = make_unique_filename(file.filename)\n    else:\n        filename = file.filename\n    file_path = dest_dir / filename\n\n    async with aiofiles.open(file_path, "wb") as buffer:\n        # Non-blocking I/O\n        while True:\n            chunk = await file.read(chunk_size)\n            if not chunk:\n                break\n            await buffer.write(chunk)\n\n    return file_path\n\n\nasync def serialize_file(task_id: str, path: str, metadata: Optional[Dict] = {}):\n    import ray\n    from ray.exceptions import TaskCancelledError\n\n    serializer = ray.get_actor("DocSerializer", namespace="openrag")\n    # Kick off the remote task\n    future = serializer.serialize_document.remote(task_id, path, metadata=metadata)\n\n    # Wait for it to complete, with timeout\n    ready, _ = await asyncio.to_thread(ray.wait, [future])\n\n    if ready:\n        try:\n            doc = await ready[0]\n            return doc\n        except TaskCancelledError:\n            raise\n        except Exception:\n            raise\n    else:\n\n        ray.cancel(future, recursive=True)\n        raise TimeoutError(f"Serialization task {task_id} timed out after seconds")\n',
            'openrag/components/test_files.py': 'import io\nimport uuid\nfrom pathlib import Path\n\nfrom fastapi import UploadFile\nimport pytest\n\nfrom components.files import save_file_to_disk\n\n\n@pytest.mark.asyncio\nasync def test_save_file_to_disk_writes_content(tmp_path: Path):\n    content = b"hello world"\n    upload = UploadFile(\n        file=io.BytesIO(content),\n        filename="test.bin",\n    )\n\n    dest_dir = tmp_path / "uploads"\n\n    saved_path = await save_file_to_disk(\n        file=upload,\n        dest_dir=dest_dir,\n        chunk_size=4\n    )\n\n    assert saved_path.exists()\n    assert saved_path.parent == dest_dir\n    assert saved_path.name == "test.bin"\n\n    with open(saved_path, "rb") as f:\n        saved_content = f.read()\n\n    assert saved_content == content\n\n\n\n@pytest.mark.asyncio\nasync def test_save_file_to_disk_with_random_prefix(tmp_path, monkeypatch):\n\n    def fake_make_unique_filename(filename: str) -> str:\n        assert filename == "test.txt"\n        return "PREFIX_1234_test.txt"\n\n    monkeypatch.setattr(\n        "components.files.make_unique_filename", fake_make_unique_filename\n    )\n\n    file_content = b"hello world"\n    upload = UploadFile(\n        filename="test.txt",\n        file=io.BytesIO(file_content),\n    )\n\n    saved_path = await save_file_to_disk(\n        file=upload,\n        dest_dir=tmp_path,\n        chunk_size=1024,\n        with_random_prefix=True,\n    )\n\n    assert saved_path.parent == tmp_path\n    assert saved_path.name == "PREFIX_1234_test.txt"\n    assert saved_path.exists()\n    assert saved_path.read_bytes() == file_content\n',
            'openrag/routers/indexer.py': 'import json\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import Any, Optional\n\nimport ray\nfrom components.files import save_file_to_disk\nfrom config import load_config\nfrom fastapi import (\n    APIRouter,\n    Depends,\n    Form,\n    HTTPException,\n    Request,\n    Response,\n    UploadFile,\n    status,\n)\nfrom fastapi.responses import JSONResponse\nfrom utils.dependencies import get_indexer, get_task_state_manager, get_vectordb\nfrom utils.logger import get_logger\n\nfrom .utils import (\n    current_user_partitions,\n    ensure_partition_role,\n    human_readable_size,\n    require_partition_editor,\n    require_task_owner,\n    validate_file_format,\n    validate_file_id,\n    validate_metadata,\n)\n\n# load logger\nlogger = get_logger()\n\n# load config\nconfig = load_config()\nDATA_DIR = config.paths.data_dir\n\nFORBIDDEN_CHARS_IN_FILE_ID = set("/")  # set(\'"<>#%{}|\\\\^`[]\')\nLOG_FILE = Path(config.paths.log_dir or "logs") / "app.json"\n\n# supported file formats or mimetypes\nACCEPTED_FILE_FORMATS = dict(config.loader["file_loaders"]).keys()\nDICT_MIMETYPES = dict(config.loader["mimetypes"])\n\n# Create an APIRouter instance\nrouter = APIRouter()\n\n\n@router.get(\n    "/supported/types",\n    description="""Get supported file types for indexing.\n\n**Response:**\nReturns a list of supported file extensions and MIME types that can be indexed by the system.\n""",\n)\nasync def get_supported_types():\n    """\n    Get a list of supported types for indexing.\n\n    Returns:\n        JSON object containing:\n        - `extensions`: List of supported file extensions.\n        - `mimetypes`: List of supported MIME types.\n    """\n    list_extensions = list(ACCEPTED_FILE_FORMATS)\n    list_mimetypes = list(DICT_MIMETYPES)\n    resp = {"extensions": list_extensions, "mimetypes": list_mimetypes}\n    return JSONResponse(content=resp)\n\n\n@router.post(\n    "/partition/{partition}/file/{file_id}",\n    description="""Upload and index a new file.\n\n**File Type Support:**\n- Supports standard file extensions listed in `/supported/types`\n- For unsupported extensions, specify `mimetype` in metadata\n\n**Metadata Format:**\nJSON string containing file metadata. Example:\n```json\n{\n    "mimetype": "text/plain",\n    "author": "John Doe",\n    ...\n}\n```\n\n**Common Mimetypes:**\n- `text/plain` - Plain text files\n- `text/markdown` - Markdown files  \n- `application/pdf` - PDF documents\n- `message/rfc822` - Email files\n\n**Response:**\nReturns 201 Created with a task status URL for tracking indexing progress.\n""",\n)\nasync def add_file(\n    request: Request,\n    partition: str,\n    file_id: str = Depends(validate_file_id),\n    file: UploadFile = Depends(validate_file_format),\n    metadata: dict = Depends(validate_metadata),\n    indexer=Depends(get_indexer),\n    task_state_manager=Depends(get_task_state_manager),\n    vectordb=Depends(get_vectordb),\n    user=Depends(require_partition_editor),\n):\n    log = logger.bind(\n        file_id=file_id,\n        partition=partition,\n        filename=file.filename,\n        user=user.get("display_name"),\n    )\n\n    if await vectordb.file_exists.remote(file_id, partition):\n        raise HTTPException(\n            status_code=status.HTTP_409_CONFLICT,\n            detail=f"File \'{file_id}\' already exists in partition {partition}",\n        )\n\n    save_dir = Path(DATA_DIR)\n    try:\n        file_path = await save_file_to_disk(file, save_dir, with_random_prefix=True)\n    except Exception as e:\n        log.exception("Failed to save file to disk.", error=str(e))\n        raise HTTPException(\n            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,\n            detail=str(e),\n        )\n\n    metadata.update({"source": str(file_path), "filename": file.filename})\n    file_stat = Path(file_path).stat()\n\n    # Append extra metadata\n    metadata["file_size"] = human_readable_size(file_stat.st_size)\n    metadata["created_at"] = datetime.fromtimestamp(file_stat.st_ctime).isoformat()\n    metadata["file_id"] = file_id\n\n    # Indexing the file\n    task = indexer.add_file.remote(\n        path=file_path, metadata=metadata, partition=partition, user=user\n    )\n    await task_state_manager.set_state.remote(task.task_id().hex(), "QUEUED")\n    await task_state_manager.set_object_ref.remote(task.task_id().hex(), {"ref": task})\n    return JSONResponse(\n        status_code=status.HTTP_201_CREATED,\n        content={\n            "task_status_url": str(\n                request.url_for("get_task_status", task_id=task.task_id().hex())\n            )\n        },\n    )\n\n\n@router.delete(\n    "/partition/{partition}/file/{file_id}",\n    description="""Delete a file from a partition.\n\n**Parameters:**\n- `partition`: The partition name\n- `file_id`: The unique identifier of the file to delete\n\n**Response:**\nReturns 204 No Content on successful deletion.\n""",\n)\nasync def delete_file(\n    partition: str,\n    file_id: str,\n    indexer=Depends(get_indexer),\n    vectordb=Depends(get_vectordb),\n    user=Depends(require_partition_editor),\n):\n    if not await vectordb.file_exists.remote(file_id, partition):\n        raise HTTPException(\n            status_code=status.HTTP_404_NOT_FOUND,\n            detail=f"\'{file_id}\' not found in partition \'{partition}\'",\n        )\n    await indexer.delete_file.remote(file_id, partition)\n    return Response(status_code=status.HTTP_204_NO_CONTENT)\n\n\n@router.put(\n    "/partition/{partition}/file/{file_id}",\n    description="""Update an existing file by replacing it.\n\n**Parameters:**\n- `partition`: The partition name\n- `file_id`: The unique identifier of the file to replace\n- `file`: New file to upload\n- `metadata`: Optional metadata as JSON string\n\n**Behavior:**\n- Deletes the existing file\n- Uploads and indexes the new file\n- Preserves the file_id\n\n**Metadata Format:**\nJSON string containing file metadata. Example:\n```json\n{\n    "mimetype": "text/plain",\n    "author": "John Doe",\n    ...\n}\n```\n\n**Response:**\nReturns 202 Accepted with a task status URL for tracking indexing progress.\n""",\n)\nasync def put_file(\n    request: Request,\n    partition: str,\n    file_id: str = Depends(validate_file_id),\n    file: UploadFile = Depends(validate_file_format),\n    metadata: dict = Depends(validate_metadata),\n    indexer=Depends(get_indexer),\n    task_state_manager=Depends(get_task_state_manager),\n    vectordb=Depends(get_vectordb),\n    user=Depends(require_partition_editor),\n):\n    log = logger.bind(file_id=file_id, partition=partition, filename=file.filename)\n\n    if not await vectordb.file_exists.remote(file_id, partition):\n        raise HTTPException(\n            status_code=status.HTTP_404_NOT_FOUND,\n            detail=f"\'{file_id}\' not found in partition \'{partition}\'",\n        )\n\n    # Delete the existing file from the vector database\n    await indexer.delete_file.remote(file_id, partition)\n\n    save_dir = Path(DATA_DIR)\n    save_dir.mkdir(parents=True, exist_ok=True)\n    file_path = save_dir / Path(file.filename).name\n    metadata.update({"source": str(file_path), "filename": file.filename})\n\n    try:\n        with open(file_path, "wb") as buffer:\n            buffer.write(await file.read())\n        log.info("File saved to disk.")\n    except Exception:\n        log.exception("Failed to save file to disk.")\n        raise HTTPException(\n            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,\n            detail="Failed to save uploaded file.",\n        )\n    file_stat = Path(file_path).stat()\n\n    # Append extra metadata\n    metadata["file_size"] = human_readable_size(file_stat.st_size)\n    metadata["created_at"] = datetime.fromtimestamp(file_stat.st_ctime).isoformat()\n    metadata["file_id"] = file_id\n\n    # Indexing the file\n    task = indexer.add_file.remote(\n        path=file_path, metadata=metadata, partition=partition\n    )\n    await task_state_manager.set_state.remote(task.task_id().hex(), "QUEUED")\n    await task_state_manager.set_object_ref.remote(task.task_id().hex(), {"ref": task})\n\n    return JSONResponse(\n        status_code=status.HTTP_202_ACCEPTED,\n        content={\n            "task_status_url": str(\n                request.url_for("get_task_status", task_id=task.task_id().hex())\n            )\n        },\n    )\n\n\n@router.patch(\n    "/partition/{partition}/file/{file_id}",\n    description="""Update file metadata without re-uploading the file.\n\n**Parameters:**\n- `partition`: The partition name\n- `file_id`: The unique identifier of the file\n- `metadata`: Metadata fields to update as JSON string\n\n**Behavior:**\n- Updates only the specified metadata fields\n- Does not require file re-upload\n- Can change the file\'s partition if user has access\n\n**Response:**\nReturns 200 OK with a success message.\n""",\n)\nasync def patch_file(\n    partition: str,\n    file_id: str = Depends(validate_file_id),\n    metadata: Optional[Any] = Depends(validate_metadata),\n    indexer=Depends(get_indexer),\n    user=Depends(require_partition_editor),\n    user_partitions=Depends(current_user_partitions),\n):\n    metadata["file_id"] = file_id\n\n    # Make sure partition role is valid if partition is being changed\n    if "partition" in metadata:\n        await ensure_partition_role(\n            partition=metadata["partition"],\n            user=user,\n            user_partitions=user_partitions,\n            required_role="editor",\n        )\n\n    await indexer.update_file_metadata.remote(file_id, metadata, partition, user=user)\n    return JSONResponse(\n        status_code=status.HTTP_200_OK,\n        content={"message": f"Metadata for file \'{file_id}\' successfully updated."},\n    )\n\n\n@router.post(\n    "/partition/{partition}/file/{file_id}/copy",\n    description="""Copy a file from one partition to another.\n\n**Parameters:**\n- `partition`: Destination partition name\n- `file_id`: New file ID in destination partition\n- `source_partition`: Source partition name (form data)\n- `source_file_id`: Source file ID (form data)\n- `metadata`: Optional metadata to override as JSON string\n\n**Permissions:**\n- Requires viewer access to source partition\n- Requires editor access to destination partition\n\n**Response:**\nReturns 201 Created on successful copy.\n""",\n)\nasync def copy_file_between_partitions(\n    partition: str,\n    file_id: str = Depends(validate_file_id),\n    metadata: Optional[Any] = Depends(validate_metadata),\n    source_partition: str = Form(...),\n    source_file_id: str = Form(...),\n    indexer=Depends(get_indexer),\n    user=Depends(require_partition_editor),\n    user_partitions=Depends(current_user_partitions),\n):\n    # Make sure user has access to destination partition\n    await ensure_partition_role(\n        partition=source_partition,\n        user=user,\n        user_partitions=user_partitions,\n        required_role="viewer",\n    )\n    metadata["file_id"] = file_id\n    metadata["partition"] = partition\n\n    await indexer.copy_file.remote(\n        file_id=source_file_id, metadata=metadata, partition=source_partition, user=user\n    )\n    return JSONResponse(\n        status_code=status.HTTP_201_CREATED,\n        content={"message": "File copied successfully."},\n    )\n\n\n@router.get(\n    "/task/{task_id}",\n    description="""Get the status of an indexing task.\n\n**Parameters:**\n- `task_id`: The unique task identifier returned when uploading a file\n\n**Response:**\nReturns task status information including:\n- `task_id`: The task identifier\n- `task_state`: Current state (QUEUED, RUNNING, SUCCESS, FAILED)\n- `details`: Additional task details\n- `error_url`: URL to get error details (if task failed)\n""",\n)\nasync def get_task_status(\n    request: Request,\n    task_id: str,\n    task_state_manager=Depends(get_task_state_manager),\n    task_details=Depends(require_task_owner),\n):\n    # fetch task state\n    state = await task_state_manager.get_state.remote(task_id)\n    if state is None:\n        raise HTTPException(\n            status_code=status.HTTP_404_NOT_FOUND,\n            detail=f"Task \'{task_id}\' not found.",\n        )\n\n    # format the response\n    content: dict[str, Any] = {\n        "task_id": task_id,\n        "task_state": state,\n        "details": task_details,\n    }\n\n    if state == "FAILED":\n        content["error_url"] = str(request.url_for("get_task_error", task_id=task_id))\n\n    return JSONResponse(status_code=status.HTTP_200_OK, content=content)\n\n\n@router.get(\n    "/task/{task_id}/error",\n    description="""Get error details for a failed task.\n\n**Parameters:**\n- `task_id`: The unique task identifier\n\n**Response:**\nReturns error information including:\n- `task_id`: The task identifier\n- `traceback`: Error traceback as an array of lines\n\n**Note:** Only available if task state is FAILED.\n""",\n)\nasync def get_task_error(\n    task_id: str,\n    task_state_manager=Depends(get_task_state_manager),\n    task_details=Depends(require_task_owner),\n):\n    try:\n        error = await task_state_manager.get_error.remote(task_id)\n        if error is None:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=f"No error found for task \'{task_id}\'.",\n            )\n        return {"task_id": task_id, "traceback": error.splitlines()}\n    except HTTPException:\n        raise\n    except Exception:\n        raise HTTPException(\n            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,\n            detail="Failed to retrieve task error.",\n        )\n\n\n@router.get(\n    "/task/{task_id}/logs",\n    description="""Get logs for a specific task.\n\n**Parameters:**\n- `task_id`: The unique task identifier\n- `max_lines`: Maximum number of log lines to return (default: 100)\n\n**Response:**\nReturns task logs including:\n- `task_id`: The task identifier\n- `logs`: Array of log entries with timestamps and messages\n\n**Note:** Logs are returned in chronological order (oldest first).\n""",\n)\nasync def get_task_logs(\n    task_id: str, max_lines: int = 100, task_details=Depends(require_task_owner)\n):\n    try:\n        if not LOG_FILE.exists():\n            raise HTTPException(status_code=500, detail="Log file not found.")\n\n        logs = []\n        with open(LOG_FILE, "r", errors="replace") as f:\n            for line in reversed(list(f)):\n                try:\n                    record = json.loads(line).get("record", {})\n                    if record.get("extra", {}).get("task_id") == task_id:\n                        logs.append(\n                            f"{record[\'time\'][\'repr\']} - {record[\'level\'][\'name\']} - {record[\'message\']} - {(record[\'extra\'])}"\n                        )\n                        if len(logs) >= max_lines:\n                            break\n                except json.JSONDecodeError:\n                    continue\n\n        if not logs:\n            raise HTTPException(\n                status_code=404, detail=f"No logs found for task \'{task_id}\'"\n            )\n\n        return JSONResponse(\n            content={"task_id": task_id, "logs": logs[::-1]}\n        )  # restore order\n    except HTTPException:\n        raise\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f"Failed to fetch logs: {str(e)}")\n\n\n@router.delete(\n    "/task/{task_id}",\n    name="cancel_task",\n    description="""Cancel a running or queued task.\n\n**Parameters:**\n- `task_id`: The unique task identifier\n\n**Behavior:**\n- Sends cancellation signal to the task\n- Recursively cancels all subtasks\n- Does not guarantee immediate cancellation\n\n**Response:**\nReturns confirmation message that cancellation signal was sent.\n""",\n)\nasync def cancel_task(\n    task_id: str,\n    task_state_manager=Depends(get_task_state_manager),\n    task_details=Depends(require_task_owner),\n):\n    try:\n        obj_ref = await task_state_manager.get_object_ref.remote(task_id)\n        if obj_ref is None:\n            raise HTTPException(404, f"No ObjectRef stored for task {task_id}")\n\n        ray.cancel(obj_ref["ref"], recursive=True)\n        return {"message": f"Cancellation signal sent for task {task_id}"}\n    except Exception as e:\n        logger.exception("Failed to cancel task.")\n        raise HTTPException(status_code=500, detail=str(e))\n',
            'openrag/routers/utils.py': 'import json\nimport os\nfrom pathlib import Path\nfrom typing import Any, Optional\n\nimport consts\nfrom config import load_config\nfrom fastapi import Depends, Form, HTTPException, Request, UploadFile, status\nfrom openai import AsyncOpenAI\nfrom utils.dependencies import get_task_state_manager, get_vectordb\nfrom utils.logger import get_logger\n\n# load config\nconfig = load_config()\nlogger = get_logger()\ntask_state_manager = get_task_state_manager()\n\nSUPER_ADMIN_MODE = os.getenv("SUPER_ADMIN_MODE", "false").lower() == "true"\nDATA_DIR = config.paths.data_dir\n\nFORBIDDEN_CHARS_IN_FILE_ID = set("/")  # set(\'"<>#%{}|\\\\^`[]\')\nLOG_FILE = Path(config.paths.log_dir or "logs") / "app.json"\n\n# supported file formats or mimetypes\nACCEPTED_FILE_FORMATS = dict(config.loader["file_loaders"]).keys()\nDICT_MIMETYPES = dict(config.loader["mimetypes"])\n\nROLE_HIERARCHY = {\n    "viewer": 1,\n    "editor": 2,\n    "owner": 3,\n}\n\n\ndef current_user(request: Request):\n    """Return the authenticated user from request.state"""\n    return request.state.user\n\n\ndef current_user_partitions(request: Request):\n    """Return the authenticated user\'s partitions from request.state"""\n    return request.state.user_partitions\n\n\ndef current_user_or_admin_partitions(request: Request):\n    """Return the authenticated user\'s partitions from request.state, or all partitions if admin"""\n    user = request.state.user\n    if user.get("is_admin") and SUPER_ADMIN_MODE:\n        return [{"partition": "all", "created_at": 0, "role": "owner"}]\n    return request.state.user_partitions\n\n\ndef current_user_or_admin_partitions_list(request: Request):\n    """Return the authenticated user\'s partitions from request.state, or all partitions if admin"""\n    return [p["partition"] for p in current_user_or_admin_partitions(request)]\n\n\ndef partitions_with_details(request: Request):\n    return current_user_or_admin_partitions(request)\n\n\ndef request_partition(request: Request):\n    """Return the partition from path params"""\n    return request.path_params.get("partition", None)\n\n\ndef request_partitions(request: Request):\n    """Return the partitions from query params"""\n    partitions = request.query_params.getlist("partitions")\n    return partitions\n\n\ndef request_task_id(request: Request):\n    """Return the task_id from path params"""\n    return request.path_params.get("task_id", None)\n\n\nasync def ensure_partition_role(\n    partition: str,\n    user,\n    user_partitions,\n    required_role: str,\n):\n    """Ensure the user has at least `required_role` for the partition."""\n    # Super-admin bypass\n    vectordb = get_vectordb()\n    if SUPER_ADMIN_MODE and user.get("is_admin"):\n        return True\n\n    # Find membership\n    membership = next((p for p in user_partitions if p["partition"] == partition), None)\n\n    if not membership:\n        # Partition exists but no membership\n        partition_exists = await vectordb.partition_exists.remote(partition)\n        if partition_exists:\n            raise HTTPException(\n                status_code=status.HTTP_403_FORBIDDEN,\n                detail=f"Access to partition \'{partition}\' forbidden",\n            )\n        else:\n            return True\n\n    user_role = membership.get("role")\n    if ROLE_HIERARCHY[user_role] < ROLE_HIERARCHY[required_role]:\n        raise HTTPException(\n            status_code=status.HTTP_403_FORBIDDEN,\n            detail=f"{required_role.capitalize()} role required for partition \'{partition}\'",\n        )\n\n    return True\n\n\nasync def require_partition_viewer(\n    partition=Depends(request_partition),\n    user=Depends(current_user),\n    user_partitions=Depends(current_user_partitions),\n):\n    await ensure_partition_role(partition, user, user_partitions, "viewer")\n    return user\n\n\nasync def require_partition_editor(\n    partition=Depends(request_partition),\n    user=Depends(current_user),\n    user_partitions=Depends(current_user_partitions),\n):\n    await ensure_partition_role(partition, user, user_partitions, "editor")\n    return user\n\n\nasync def require_partition_owner(\n    partition=Depends(request_partition),\n    user=Depends(current_user),\n    user_partitions=Depends(current_user_partitions),\n):\n    await ensure_partition_role(partition, user, user_partitions, "owner")\n    return user\n\n\nasync def require_partitions_viewer(\n    partitions=Depends(request_partitions),\n    user=Depends(current_user),\n    user_partitions=Depends(current_user_partitions),\n):\n    if SUPER_ADMIN_MODE and user.get("is_admin"):\n        return user\n    if isinstance(partitions, list) and len(partitions) == 1 and partitions[0] == "all":\n        return user\n    for partition in partitions:\n        await ensure_partition_role(partition, user, user_partitions, "viewer")\n        logger.info(f"User has viewer access to partition \'{partition}\'")\n    return user\n\n\nasync def require_task_owner(\n    task_id=Depends(request_task_id), user=Depends(current_user)\n):\n    task_details = await task_state_manager.get_details.remote(task_id)\n    if not task_details:\n        raise HTTPException(\n            status_code=status.HTTP_404_NOT_FOUND,\n            detail=f"Task \'{task_id}\' not found",\n        )\n    if task_details.get("user_id") != user.get("id"):\n        raise HTTPException(\n            status_code=status.HTTP_403_FORBIDDEN,\n            detail="You do not have permission to access this task",\n        )\n    return task_details\n\n\ndef require_admin(user=Depends(current_user)):\n    """Ensure the user has admin privileges"""\n    if not user or not user.get("is_admin", False):\n        raise HTTPException(\n            status_code=status.HTTP_403_FORBIDDEN,\n            detail="Admin privileges required",\n        )\n    return user\n\n\ndef is_file_id_valid(file_id: str) -> bool:\n    return not any(c in file_id for c in FORBIDDEN_CHARS_IN_FILE_ID)\n\n\nasync def validate_file_id(file_id: str):\n    if not is_file_id_valid(file_id):\n        raise HTTPException(\n            status_code=status.HTTP_400_BAD_REQUEST,\n            detail=f"File ID contains forbidden characters: {\', \'.join(FORBIDDEN_CHARS_IN_FILE_ID)}",\n        )\n    if not file_id.strip():\n        raise HTTPException(\n            status_code=status.HTTP_400_BAD_REQUEST, detail="File ID cannot be empty."\n        )\n    return file_id\n\n\nasync def validate_metadata(metadata: Optional[Any] = Form(None)):\n    try:\n        processed_metadata = metadata or "{}"\n        processed_metadata = json.loads(processed_metadata)\n        return processed_metadata\n    except json.JSONDecodeError:\n        raise HTTPException(\n            status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid JSON in metadata"\n        )\n\n\nasync def validate_file_format(\n    file: UploadFile,\n    metadata: dict = Depends(validate_metadata),\n):\n    file_extension = (\n        file.filename.split(".")[-1].lower() if "." in file.filename else ""\n    )\n    mimetype = metadata.get("mimetype", None)\n\n    if (\n        file_extension not in ACCEPTED_FILE_FORMATS\n        and mimetype not in DICT_MIMETYPES.keys()\n    ):\n        details = (\n            f"Unsupported file format: {file_extension} or file mimetype.\\n"\n            f"Supported formats: {\', \'.join(ACCEPTED_FILE_FORMATS)}\\n"\n            f"Supported mimetypes: {\', \'.join(DICT_MIMETYPES.keys())}"\n        )\n        raise HTTPException(\n            status_code=status.HTTP_415_UNSUPPORTED_MEDIA_TYPE,\n            detail=details,\n        )\n    return file\n\n\ndef human_readable_size(size_bytes: int) -> str:\n    """Convert bytes to a human-readable format (e.g., \'2.4 MB\')."""\n    for unit in ["B", "KB", "MB", "GB", "TB"]:\n        if size_bytes < 1024:\n            return f"{size_bytes:.2f} {unit}"\n        size_bytes /= 1024\n    return f"{size_bytes:.2f} PB"\n\n\ndef get_app_state(request: Request):\n    return request.app.state.app_state\n\n\nasync def check_llm_model_availability(request: Request):\n    models = {"VLM": config.vlm, "LLM": config.llm}\n    for model_type, param in models.items():\n        try:\n            client = AsyncOpenAI(api_key=param["api_key"], base_url=param["base_url"])\n            openai_models = await client.models.list()\n            available_models = {m.id for m in openai_models.data}\n            if param["model"] not in available_models:\n                raise HTTPException(\n                    status_code=status.HTTP_404_NOT_FOUND,\n                    detail=f"Only these models ({available_models}) are available for your `{model_type}`. Please check your configuration file.",\n                )\n        except Exception as e:\n            logger.exception("Failed to validate model", model=model_type)\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=f"Error while checking the `{model_type}` endpoint: {str(e)}",\n            )\n\n\nasync def get_partition_name(model_name, user_partitions, is_admin=False):\n    vectordb = get_vectordb()\n\n    partition_prefix = consts.PARTITION_PREFIX\n    if model_name.startswith(consts.LEGACY_PARTITION_PREFIX):\n        # XXX - This is for backward compatibility, but should eventually be removed\n        partition_prefix = consts.LEGACY_PARTITION_PREFIX\n\n    if not model_name.startswith(partition_prefix):\n        raise HTTPException(\n            status_code=status.HTTP_404_NOT_FOUND,\n            detail=f"Model not found. Model should respect this format: {consts.PARTITION_PREFIX}partition_name",\n        )\n    partition = model_name.split(partition_prefix)[1]\n    if partition != "all" and not await vectordb.partition_exists.remote(partition):\n        raise HTTPException(\n            status_code=status.HTTP_404_NOT_FOUND,\n            detail=f"Partition `{partition}` not found for given model `{model_name}`",\n        )\n    if (\n        partition != "all"\n        and partition not in user_partitions\n        and not (is_admin and SUPER_ADMIN_MODE)\n    ):\n        raise HTTPException(\n            status_code=status.HTTP_403_FORBIDDEN,\n            detail=f"Access to model `{model_name}` is forbidden for the current user",\n        )\n    if partition == "all" and not (is_admin and SUPER_ADMIN_MODE):\n        return user_partitions\n    return [partition]\n',
        }
